'use client'

import { useState, useEffect } from 'react'

export default function Portfolio() {
  const [arts, setArts] = useState([])

  useEffect(() => {
    fetch('/api/arts')
      .then(res => res.json())
      .then(setArts)
  }, [])

  return (
    <div>
      <section className="section">
        <div className="container">
          <h2>ผลงาน</h2>
          <div className="gallery">
            {arts.map(art => (
              <div key={art._id}>
                <img src={art.image} alt={art.title} />
                <p>{art.title}</p>
                <p>{art.price} บาท</p>
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  )
}
